392	        ready!(crate::trace::trace_leaf());
393	
394	        // Keep track of task budget
395	        #[cfg(all(tokio_unstable, feature = "tracing"))]
396	        let coop = ready!(trace_poll_op!(
397	            "poll_elapsed",
398	            crate::task::coop::poll_proceed(cx),
399	        ));
400	
401	        #[cfg(any(not(tokio_unstable), not(feature = "tracing")))]
402	        let coop = ready!(crate::task::coop::poll_proceed(cx));
403	
404	        let mut this = self.project();
405	        let timer = match this.timer.as_mut().as_pin_mut() {
406	            Some(timer) => timer,
407	            None => {
408	                let handle = this.driver;
409	
410	                #[cfg(all(tokio_unstable, feature = "tracing"))]
411	                {
412	                    let clock = handle.driver().clock();
413	                    let time_source = handle.driver().time().time_source();
414	                    let now = time_source.now(clock);
415	                    let tick = time_source.deadline_to_tick(*this.deadline);
416	                    tracing::trace!(
417	                        target: "runtime::resource::state_update",
418	                        duration = tick.saturating_sub(now),
419	                        duration.unit = "ms",
420	                        duration.op = "override",
421	                    );
422	                }
423	
424	                let timer = Timer::new(handle.clone(), *this.deadline);
425	                this.timer.set(Some(timer));
426	                let mut timer = this.timer.as_pin_mut().unwrap();
427	                timer.as_mut().init(*this.deadline);
428	                timer
429	            }
430	        };
431	
432	        let result = timer.poll_elapsed(cx).map(move |r| {
433	            coop.made_progress();
