116	impl StateCell {
117	    fn new() -> Self {
118	        Self {
119	            state: AtomicU64::new(STATE_DEREGISTERED),
120	            result: UnsafeCell::new(Ok(())),
121	            waker: AtomicWaker::new(),
122	        }
123	    }
